class Person:
    def __init__(self, name):
        self.name = name

p = Person('Alice')
print(p.name)

class Dog:
    def __init__(self, name):
        self.name = name

    def bark(self):
        print('Woof!')

d = Dog('Buddy')
d.bark()

class Book:
    def __init__(self, title):
        self.title = title

    def __str__(self):
        return self.title

b = Book('Python Basics')
print(b)

class Animal:
    def __init__(self, name):
        self.name = name

class Cat(Animal):
    def __init__(self, name, color):
        super().__init__(name)
        self.color = color

c = Cat('Tom', 'Orange')
print(c.name)

class Account:
    def __init__(self):
        self.__balance = 100

    def get_balance(self):
        return self.__balance

acc = Account()
print(acc.get_balance())

class Temperature:
    def __init__(self, celsius):
        self.celsius = celsius

    @property
    def fahrenheit(self):
        return self.celsius * 9/5 + 32

t = Temperature(0)
print(t.fahrenheit)

class Vector:
    def __init__(self, x, y):
        self.x = x
        self.y = y

    def __add__(self, other):
        return Vector(self.x + other.x, self.y + other.y)

    def __str__(self):
        return f'({self.x}, {self.y})'

v1 = Vector(1, 2)
v2 = Vector(3, 4)
print(v1 + v2)

class Stack:
    def __init__(self):
        self.items = []

    def __len__(self):
        return len(self.items)

s = Stack()
s.items.append(1)
s.items.append(2)
print(len(s))

class Animal:
    def greet(self):
        return 'Animal'

class Dog(Animal):
    def greet(self):
        return 'Dog'

d = Dog()
print(d.greet())

class Math:
    @classmethod
    def add(cls, x, y):
        return x + y

print(Math.add(3, 4))

class Math2:
    @staticmethod
    def multiply(x, y):
        return x * y

print(Math2.multiply(3, 4))

